"use client"

import React, { useState } from 'react';
import axios from 'axios';
import styles from './pill.module.css';
import { DRUG_SHAPES, COLOR_CLASSES } from './constants/pillFilters';

interface PillItem {
    itemSeq: string;
    itemName: string;
    entpName: string;
    chart: string;
    itemImage: string;
    printFront: string;
    drugShape: string;
    colorClass1: string;
    efficacy: string; 
}

export default function PillSearchPage() {
    const [printFront, setPrintFront] = useState('');
    const [drugShape, setDrugShape] = useState('');
    const [colorClass1, setColorClass1] = useState('');
    
    const [results, setResults] = useState<PillItem[]>([]);
    const [loading, setLoading] = useState(false);
    const [hasSearched, setHasSearched] = useState(false);

    const handleSearch = async () => {
        if (!printFront && !drugShape && !colorClass1) {
            alert("최소 한 가지 이상의 검색 조건을 선택해주세요!");
            return;
        }

        setLoading(true);
        setHasSearched(true); 
        setResults([]); // 이전 검색 결과 초기화

        try {
            const response = await axios.get(`http://localhost:8080/api/pill/search`, {
                params: { printFront, drugShape, colorClass1 }
            });
            
            if (Array.isArray(response.data)) {
                setResults(response.data);
            }
        } catch (error) {
            console.error("알약 식별 검색 실패:", error);
            alert("검색 중 오류가 발생했습니다. 백엔드 서버 상태를 확인해주세요.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className={styles.container}>
            <header className={styles.header}>
                <h2 className={styles.title}>🔍 알약 식별 검색</h2>
                <p className={styles.subTitle}>알약의 겉모습(문자, 모양, 색상)으로 효능까지 한 번에 찾으세요.</p>
            </header>

            <div className={styles.searchFilter}>
                <div className={styles.inputGroup}>
                    <label>식별문자</label>
                    <input 
                        type="text" 
                        placeholder="예: TY, 500" 
                        value={printFront}
                        onChange={(e) => setPrintFront(e.target.value)}
                    />
                </div>

                <div className={styles.inputGroup}>
                    <label>모양</label>
                    <select value={drugShape} onChange={(e) => setDrugShape(e.target.value)}>
                        {DRUG_SHAPES.map((shape) => (
                            <option key={shape.value} value={shape.value}>{shape.label}</option>
                        ))}
                    </select>
                </div>

                <div className={styles.inputGroup}>
                    <label>색상</label>
                    <select value={colorClass1} onChange={(e) => setColorClass1(e.target.value)}>
                        {COLOR_CLASSES.map((color) => (
                            <option key={color.value} value={color.value}>{color.label}</option>
                        ))}
                    </select>
                </div>

                <button onClick={handleSearch} className={styles.searchBtn}>검색하기</button>
            </div>

            <hr className={styles.hr} />

            <div className={styles.resultContainer}>
                {loading ? (
                    <div className={styles.loadingWrapper}>
                        <p className={styles.statusMsg}>알약을 식별하고 효능을 분석 중입니다... 🧪</p>
                    </div>
                ) : results.length > 0 ? (
                    <div className={styles.pillGrid}>
                        {results.map((pill) => (
                            <div key={pill.itemSeq} className={styles.pillCard}>
                                <div className={styles.pillImg}>
                                    <img 
                                        src={pill.itemImage || "/img/no_drug_img.png"} 
                                        alt={pill.itemName} 
                                        onError={(e) => e.currentTarget.src = "/img/no_drug_img.png"}
                                    />
                                </div>
                                <div className={styles.pillInfo}>
                                    <span className={styles.entpName}>{pill.entpName}</span>
                                    <h3 className={styles.drugName}>{pill.itemName}</h3>
                                    
                                    <div className={styles.metaInfo}>
                                        <span>{pill.drugShape}</span>
                                        <span className={styles.divider}>|</span>
                                        <span>{pill.colorClass1}</span>
                                        <span className={styles.divider}>|</span>
                                        <span>{pill.printFront || '식별문자 없음'}</span>
                                    </div>

                                    {pill.efficacy && pill.efficacy !== "정보 없음" ? (
                                        <div className={styles.efficacyBox}>
                                            <strong>💡 효능/효과 (네이버 지식백과 기반)</strong>
                                            <p>{pill.efficacy}</p>
                                        </div>
                                    ) : (
                                        <a 
                                            href={`https://terms.naver.com/search.naver?query=${pill.itemName}`} 
                                            target="_blank" 
                                            rel="noopener noreferrer"
                                            className={styles.naverBtn}
                                        >
                                            ✨ 효능 확인하기 (네이버)
                                        </a>
                                    )}
                                    <p className={styles.chartDesc}>{pill.chart}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : hasSearched && (
                    <p className={styles.statusMsg}>검색 결과가 없습니다. 조건을 변경해 보세요.</p>
                )}
            </div>
        </div>
    );
}